glsl3.vert:
  precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
  attribute vec3 a_position;
  attribute vec2 a_uv0;
  out vec2 uv0;
  void main () {
      gl_Position = cc_matViewProj * vec4(a_position,1);
      uv0 = a_uv0;
}

glsl3.frag:
    precision highp float;
    in vec2 uv0;
    uniform sampler2D texture;
    uniform PROPERTIES {
      vec4 color1;
      vec4 color2;
      vec4 color3;
      float opacity;
  };
vec3 gradient(vec3 c1, vec3 c2, vec3 c3, float grad){
    vec3 o = mix(c1, c3, grad);
    float u = 1.0 - abs(grad * 2.0 - 1.0);
    o = mix(o, c2, u);
    return o;
}
    void main() {
    vec4 tex = texture2D(texture, uv0);
    float l = dot(tex.rgb, vec3(0.299, 0.587, 0.114));
    vec3 c1 = vec3(color1.r,color1.g,color1.b);
    vec3 c2 = vec3(color2.r,color2.g,color2.b);
    vec3 c3 = vec3(color3.r,color3.g,color3.b);
    vec4 fragColor3 = vec4(gradient(c3, c2, c1, l), 1.0);
    gl_FragColor = fragColor3;
    }

